def get_user_info():
    name = input("Enter your name: ").strip()
    age = int(input("Enter your age: "))
    favorite_color = input("Enter your favorite color: ").strip()
    return name, age, favorite_color

def repeat_greetings(name: str, times: int):
    for i in range(1, times + 1):
        print(f"Greeting {i}: Hello, {name}! 👋")
        if i % 3 == 0:
            print("That's a multiple of 3, nice!")

def color_message(color: str):
    colors = ["red", "blue", "green", "yellow", "purple", "orange"]
    if color.lower() in colors:
        print(f"{color.capitalize()} is a nice choice!")
    else:
        print(f"{color.capitalize()} is unique!")

def math_challenge(age: int):
    print(f"Let's do some fun math with your age: {age}")
    squared = age ** 2
    print(f"Your age squared is: {squared}")
    factorial = 1
    for i in range(1, age + 1):
        factorial *= i
    print(f"Factorial of your age is: {factorial}")

def favorites_list():
    items = []
    print("Enter 3 of your favorite things:")
    for i in range(3):
        item = input(f"Item {i + 1}: ")
        items.append(item)
    print("Your favorites are:", ", ".join(items))

def main():
    print("Welcome to the advanced greeting program!")
    name, age, color = get_user_info()
    repeat_greetings(name, 5)
    color_message(color)
    math_challenge(age)
    favorites_list()
    print("Thank you for using the program! Goodbye!")

if __name__ == "__main__":
    main()
